(window.webpackJsonp=window.webpackJsonp||[]).push([[405],{1647:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">command</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">obstacles</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">x</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">y</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> robot = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">command, obstacles, x, y</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> len=command.length\\n  <span class=\\"hljs-keyword\\">let</span> moves={\\n    <span class=\\"hljs-attr\\">U</span>:[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">1</span>],\\n    <span class=\\"hljs-attr\\">R</span>:[<span class=\\"hljs-number\\">1</span>,<span class=\\"hljs-number\\">0</span>]\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> allDx=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> allDy=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> c <span class=\\"hljs-keyword\\">of</span> command){\\n    allDx+=moves[c][<span class=\\"hljs-number\\">0</span>]\\n    allDy+=moves[c][<span class=\\"hljs-number\\">1</span>]\\n  }\\n  \\n  <span class=\\"hljs-keyword\\">let</span> xStep=<span class=\\"hljs-built_in\\">Math</span>.floor(x/allDx)\\n  <span class=\\"hljs-keyword\\">let</span> yStep=<span class=\\"hljs-built_in\\">Math</span>.floor(y/allDy)\\n  <span class=\\"hljs-keyword\\">let</span> leastStep=<span class=\\"hljs-built_in\\">Math</span>.min(xStep,yStep)\\n  <span class=\\"hljs-keyword\\">let</span> start=[leastStep*allDx,leastStep*allDy]\\n  <span class=\\"hljs-keyword\\">let</span> res=moveOnce(start,[<span class=\\"hljs-literal\\">null</span>,<span class=\\"hljs-literal\\">null</span>])\\n  <span class=\\"hljs-comment\\">// console.log(res,start)</span>\\n  <span class=\\"hljs-keyword\\">if</span>(res!==<span class=\\"hljs-number\\">1</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n  \\n  \\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;obstacles.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> [ox,oy]=obstacles[i]\\n    <span class=\\"hljs-keyword\\">if</span>(ox&gt;x || oy&gt;y)<span class=\\"hljs-keyword\\">continue</span>\\n    <span class=\\"hljs-keyword\\">let</span> xStep=<span class=\\"hljs-built_in\\">Math</span>.floor(ox/allDx)\\n    <span class=\\"hljs-keyword\\">let</span> yStep=<span class=\\"hljs-built_in\\">Math</span>.floor(oy/allDy)\\n    <span class=\\"hljs-keyword\\">let</span> leastStep=<span class=\\"hljs-built_in\\">Math</span>.min(xStep,yStep)\\n    <span class=\\"hljs-keyword\\">let</span> start=[leastStep*allDx,leastStep*allDy]\\n    <span class=\\"hljs-keyword\\">let</span> res=moveOnce(start,obstacles[i])\\n    <span class=\\"hljs-keyword\\">if</span>(res===<span class=\\"hljs-number\\">-1</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n  }\\n  \\n\\n  \\n  \\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">moveOnce</span>(<span class=\\"hljs-params\\">point,obsP</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> [cx,cy]=point\\n    <span class=\\"hljs-keyword\\">let</span> [ox,oy]=obsP\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(cx===ox &amp;&amp; cy===oy)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n      <span class=\\"hljs-keyword\\">if</span>(cx===x &amp;&amp; cy===y)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">1</span>\\n      <span class=\\"hljs-keyword\\">let</span> [dx,dy]=moves[command[i]]\\n      <span class=\\"hljs-keyword\\">let</span> nx=dx+cx\\n      <span class=\\"hljs-keyword\\">let</span> ny=dy+cy\\n      <span class=\\"hljs-keyword\\">if</span>(nx&gt;x || ny&gt;y)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n      cx=nx\\n      cy=ny\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n  }\\n\\n};\\n</code></pre>\\n"],"titleSlug":"programmable-robot","hasThinking":false,"content":"<p>\u529b\u6263\u56e2\u961f\u4e70\u4e86\u4e00\u4e2a\u53ef\u7f16\u7a0b\u673a\u5668\u4eba\uff0c\u673a\u5668\u4eba\u521d\u59cb\u4f4d\u7f6e\u5728\u539f\u70b9<code>(0, 0)</code>\u3002\u5c0f\u4f19\u4f34\u4e8b\u5148\u7ed9\u673a\u5668\u4eba\u8f93\u5165\u4e00\u4e32\u6307\u4ee4<code>command</code>\uff0c\u673a\u5668\u4eba\u5c31\u4f1a<strong>\u65e0\u9650\u5faa\u73af</strong>\u8fd9\u6761\u6307\u4ee4\u7684\u6b65\u9aa4\u8fdb\u884c\u79fb\u52a8\u3002\u6307\u4ee4\u6709\u4e24\u79cd\uff1a</p>\\n\\n<ol>\\n\\t<li><code>U</code>: \u5411<code>y</code>\u8f74\u6b63\u65b9\u5411\u79fb\u52a8\u4e00\u683c</li>\\n\\t<li><code>R</code>: \u5411<code>x</code>\u8f74\u6b63\u65b9\u5411\u79fb\u52a8\u4e00\u683c\u3002</li>\\n</ol>\\n\\n<p>\u4e0d\u5e78\u7684\u662f\uff0c\u5728 xy \u5e73\u9762\u4e0a\u8fd8\u6709\u4e00\u4e9b\u969c\u788d\u7269\uff0c\u4ed6\u4eec\u7684\u5750\u6807\u7528<code>obstacles</code>\u8868\u793a\u3002\u673a\u5668\u4eba\u4e00\u65e6\u78b0\u5230\u969c\u788d\u7269\u5c31\u4f1a\u88ab<strong>\u635f\u6bc1</strong>\u3002</p>\\n\\n<p>\u7ed9\u5b9a\u7ec8\u70b9\u5750\u6807<code>(x, y)</code>\uff0c\u8fd4\u56de\u673a\u5668\u4eba\u80fd\u5426<strong>\u5b8c\u597d</strong>\u5730\u5230\u8fbe\u7ec8\u70b9\u3002\u5982\u679c\u80fd\uff0c\u8fd4\u56de<code>true</code>\uff1b\u5426\u5219\u8fd4\u56de<code>false</code>\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>command = &quot;URR&quot;, obstacles = [], x = 3, y = 2\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>U(0, 1) -&gt; R(1, 1) -&gt; R(2, 1) -&gt; U(2, 2) -&gt; R(3, 2)\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>command = &quot;URR&quot;, obstacles = [[2, 2]], x = 3, y = 2\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n<strong>\u89e3\u91ca\uff1a</strong>\u673a\u5668\u4eba\u5728\u5230\u8fbe\u7ec8\u70b9\u524d\u4f1a\u78b0\u5230(2, 2)\u7684\u969c\u788d\u7269\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>command = &quot;URR&quot;, obstacles = [[4, 2]], x = 3, y = 2\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>\u5230\u8fbe\u7ec8\u70b9\u540e\uff0c\u518d\u78b0\u5230\u969c\u788d\u7269\u4e5f\u4e0d\u5f71\u54cd\u8fd4\u56de\u7ed3\u679c\u3002</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u9650\u5236\uff1a</strong></p>\\n\\n<ol>\\n\\t<li><code>2 &lt;= command\u7684\u957f\u5ea6 &lt;= 1000</code></li>\\n\\t<li><code>command</code>\u7531<code>U\uff0cR</code>\u6784\u6210\uff0c\u4e14\u81f3\u5c11\u6709\u4e00\u4e2a<code>U</code>\uff0c\u81f3\u5c11\u6709\u4e00\u4e2a<code>R</code></li>\\n\\t<li><code>0 &lt;= x &lt;= 1e9, 0 &lt;= y &lt;= 1e9</code></li>\\n\\t<li><code>0 &lt;= obstacles\u7684\u957f\u5ea6 &lt;= 1000</code></li>\\n\\t<li><code>obstacles[i]</code>\u4e0d\u4e3a\u539f\u70b9\u6216\u8005\u7ec8\u70b9</li>\\n</ol>\\n","title":"LCP 03. \u673a\u5668\u4eba\u5927\u5192\u9669","relatedTags":[],"difficult":"Middle","lang":["javascript"],"uniqueID":"LCP 03"}')}}]);